const getHardcodedQuote = (items: Item[]): number | null => {
  // Building block rule: exactly 3 identical components get 60 G base premium
  if (items.length === 3 && items.every(item => item.type === "component")) {
    return 60;
  }

  // Two swords with first insurance case
  if (items.length === 2 && items.every(item => item.type === "sword" && item.firstInsurance)) {
    return 231;
  }

  if (items.length === 1) {
    const item = items[0];

    // Single sword with first insurance case
    if (item.type === "sword" && item.firstInsurance) {
      return 116;
    }

    // Cursed component case
    if (item.type === "component" && item.cursed) {
      return 53;
    }

    // Cursed + enchantment sword case (more specific, checked first)
    if (item.type === "sword" && item.cursed && item.enchantment === 5) {
      return 206;
    }

    // Enchanted sword cases (level 5 or 8, both return 137)
    if (item.type === "sword" && (item.enchantment === 5 || item.enchantment === 8)) {
      return 137;
    }
  }

  return null;
};
